import"./hoisted.DahsVtqp.js";const e=document.getElementById("triggerBtn"),s=document.getElementById("keyword"),t=document.getElementById("statusMsg");e?.addEventListener("click",async()=>{const n=s.value.trim();if(!n)return alert("Ange ett ämne först!");e.setAttribute("disabled","true"),e.innerText="Startar...";try{if((await fetch("/api/generate",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({keyword:n})})).ok)t.innerText="Generering påbörjad! Uppdatera sidan om en minut för att se loggen.",t.style.color="green";else throw new Error("Misslyckades att starta")}catch{t.innerText="Ett fel uppstod.",t.style.color="red"}finally{e.removeAttribute("disabled"),e.innerText="Starta Generering"}});
